// src/Events/EventCommentSection.jsx
import {useCallback, useContext, useEffect, useState} from "react";
import { AuthContext } from "../AuthContext";
import CommentSection from "../CommentSection";

export default function EventCommentSection({
                                                eventId,
                                                eventStatus,
                                                rsvp
                                            }) {
    const { user } = useContext(AuthContext);

    const [comments, setComments] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    const [newComment, setNewComment] = useState("");

    /* =========================
       PERMISSIONS
    ========================= */
    const canComment =
        user &&
        rsvp === "GOING" &&
        eventStatus === "ENDED";

    /* ===================== FETCH POST ===================== */

    const fetchEvent = useCallback(async () => {
        if (!postId) return;

        const usernameParam = user?.username
            ? `?username=${encodeURIComponent(user.username)}`
            : "";

        const res = await fetch(`/api/events${usernameParam}`);
        const data = await res.json();

        const found = Array.isArray(data)
            ? data.find(p => p.id === postId)
            : null;

        setPost(found || null);
    }, [postId, user?.username]);


    /* ===================== FETCH COMMENTS ===================== */

    const fetchComments = useCallback(async () => {
        if (!eventId) return;

        const usernameParam = user?.username
            ? `?username=${encodeURIComponent(user.username)}`
            : "";

        const res = await fetch(
            `/api/events/${eventId}/comments${usernameParam}`
        );

        if (!res.ok) {
            setComments([]);
            return;
        }

        const data = await res.json();
        setComments(Array.isArray(data) ? data : []);
    }, [postId, user?.username]);


    useEffect(() => {
        if (!eventId) return;
        let alive = true;

        (async () => {
            setLoading(true);
            await Promise.all([fet(), fetchComments()]);
            if (alive) setLoading(false);
        })();

        return () => {
            alive = false;
        };
    }, [postId, fetchPost, fetchComments]);
    /* =========================
       SUBMIT COMMENT / REPLY
    ========================= */
    const submitComment = async (e, parentId = null) => {
        e.preventDefault();

        if (!canComment) return;

        const text = newComment.trim();
        if (!text) return;

        try {
            const res = await fetch(
                `/api/events/${eventId}/comments?requesterEmail=${encodeURIComponent(
                    user.email
                )}`,
                {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        comment: text,
                        parentId
                    })
                }
            );

            if (!res.ok) {
                const body = await res.json().catch(() => ({}));
                throw new Error(body.message || "Failed to post comment");
            }

            setNewComment("");
            fetchComments();
        } catch (e) {
            alert(e.message);
        }
    };

    /* =========================
       DELETE COMMENT (ADMIN / OWNER)
    ========================= */
    const deleteComment = async (commentId) => {
        if (!user) return;

        if (!window.confirm("Delete this comment?")) return;

        try {
            const res = await fetch(
                `/api/comments/${commentId}?requesterEmail=${encodeURIComponent(
                    user.email
                )}`,
                { method: "DELETE" }
            );

            if (!res.ok) {
                throw new Error("Delete failed");
            }

            fetchComments();
        } catch (e) {
            alert(e.message || "Unable to delete comment");
        }
    };

    /* =========================
       RENDER STATES
    ========================= */
    if (loading) {
        return <div className="muted">Loading reviews…</div>;
    }

    return (
        <section className="event-comments">
            <h3 style={{ marginTop: 24 }}>Reviews & Feedback</h3>

            {/* Permission hints */}
            {!user && (
                <p className="muted">
                    Log in to leave a review.
                </p>
            )}

            {user && rsvp !== "GOING" && (
                <p className="muted">
                    Only attendees can leave a review.
                </p>
            )}

            {user && rsvp === "GOING" && eventStatus !== "ENDED" && (
                <p className="muted">
                    Reviews open after the event ends.
                </p>
            )}

            {error && <div className="error">{error}</div>}

            <CommentSection
                comments={comments}
                user={user}
                newComment={newComment}
                setNewComment={setNewComment}
                onSubmit={submitComment}
                onDelete={deleteComment}
                refreshComments={fetchComments}
            />

            {!canComment && (
                <div className="muted" style={{ marginTop: 8 }}>
                    You cannot post a review at this time.
                </div>
            )}
        </section>
    );
}
